@Composable private fun OnboardingGuide(finish:()->Unit){var page by remember{mutableIntStateOf(0)};val pages=listOf(Triple("🌊",tr("Добре дошли","Welcome"),tr("Следете актуалните измервания и прогнозата за избраната морска станция.","Track current observations and forecasts for the selected marine station.")),Triple("📈",tr("Измервания и графики","Measurements and charts"),tr("Плъзнете екрана нагоре, за да видите историята за море, вълни, вятър и интервал. Под всяка група е посочен източникът.","Scroll up to view sea, wave, wind and interval history. Each group shows its data source.")),Triple("🏄",tr("Морски спортове","Marine sports"),tr("Цветът е ориентировъчна оценка по различни критерии за всеки спорт. Дневните активности използват изгрев и залез; оценката не е гаранция за безопасност.","Colors are indicative ratings based on sport-specific criteria. Daytime activities use sunrise and sunset; ratings are not a safety guarantee.")),Triple("🎚",tr("Вашите критерии","Your criteria"),tr("От подробностите на спорта можете да настройвате лимити, ниво на опит и часовете за оценка. Винаги проверявайте местните предупреждения.","From sport details you can adjust limits, experience and evaluation hours. Always check local warnings.")));val current=pages[page];AlertDialog(onDismissRequest={},icon={Text(current.first,fontSize=42.sp)},title={Text(current.second)},text={Column(verticalArrangement=Arrangement.spacedBy(12.dp)){Text(current.third);LinearProgressIndicator(progress={(page+1)/pages.size.toFloat()},modifier=Modifier.fillMaxWidth());Text("${page+1}/${pages.size}",style=MaterialTheme.typography.labelSmall)}},confirmButton={Button(onClick={if(page<pages.lastIndex)page++ else finish()}){Text(if(page<pages.lastIndex)tr("Напред","Next")else tr("Започни","Start"))}},dismissButton={if(page>0)TextButton(onClick={page--}){Text(tr("Назад","Back"))}else TextButton(onClick=finish){Text(tr("Пропусни","Skip"))}})}

