        Row(verticalAlignment=Alignment.CenterVertically){Column(Modifier.weight(1f)){Text(destination.name,fontSize=24.sp,fontWeight=FontWeight.Bold);Text("ПРОГНОЗНИ ДАННИ",color=MaterialTheme.colorScheme.primary,fontWeight=FontWeight.Bold)};OutlinedButton(onClick={choose=true}){Icon(Icons.Default.Place,null);Spacer(Modifier.width(6.dp));Text("Смени")};IconButton(onClick=refresh){Icon(Icons.Default.Refresh,"Обнови")}}
        Text("Източник: Open-Meteo Marine • прогнозна стойност",style=MaterialTheme.typography.bodySmall)
