            SingleChoiceSegmentedButtonRow(Modifier.fillMaxWidth()){listOf(1 to "24 часа",3 to "3 дни",7 to "7 дни").forEachIndexed{i,(value,label)->SegmentedButton(period==value,{period=value;selectedDate=null},SegmentedButtonDefaults.itemShape(i,3)){Text(label)}}}
            if(period>1){LazyRow(horizontalArrangement=Arrangement.spacedBy(8.dp)){items(visibleDays){day->ForecastDayCard(day,atmospheric.forecast,activeDay?.date==day.date){selectedDate=day.date}}}}
            Text(if(period==1)"Следващите 24 часа" else "Почасово за ${activeDay?.date?.format(DateTimeFormatter.ofPattern("dd.MM"))?:"избрания ден"}",fontWeight=FontWeight.Bold)
            LazyRow(horizontalArrangement=Arrangement.spacedBy(8.dp)){items(hourly){ForecastHour(it,atmospheric.forecast)}}
            if(period>1){Text("Обобщение",fontWeight=FontWeight.Bold);visibleDays.forEach{ForecastDayRow(it,atmospheric.forecast)}}
            banner?.let{Spacer(Modifier.height(8.dp));SponsoredCompactBanner(it,{dismiss(it)})}
        }
    }
    if(choose)ModalBottomSheet(onDismissRequest={choose=false}){Text("Избери дестинация",Modifier.padding(20.dp),fontSize=22.sp,fontWeight=FontWeight.Bold);destinations.forEach{d->ListItem(headlineContent={Text(d.name)},modifier=Modifier.clickable{select(d.id);choose=false})};Spacer(Modifier.height(20.dp))}
}
