        val status=freshness(o.measuredAtUtc, cached=o.isCached);Text(freshnessTitle(status),color=when(status){Freshness.CURRENT->Color(0xFF198754);Freshness.STALE->Color(0xFFE09F00);else->MaterialTheme.colorScheme.error},fontWeight=FontWeight.Bold)
    }}
}
