@Composable private fun MeasurementCharts(observations:List<BuoyObservation>){val ordered=observations.filter{it.measuredAtUtc!=null}.distinctBy{it.measuredAtUtc}.sortedBy{it.measuredAtUtc}.takeLast(4);if(ordered.isEmpty())return;HorizontalDivider();Text(tr("Графики на измерванията","Measurement charts"),fontWeight=FontWeight.SemiBold,style=MaterialTheme.typography.bodyMedium);ElevatedCard(Modifier.fillMaxWidth()){Column(Modifier.padding(12.dp),verticalArrangement=Arrangement.spacedBy(14.dp)){MeasurementChart(tr("Температура на морето","Sea temperature"),"°C",ordered.mapNotNull{o->o.waterTemperatureC?.let{o.measuredAtUtc!! to it}},1);HorizontalDivider();MeasurementChart(tr("Височина на вълните","Wave height"),"m",ordered.mapNotNull{o->o.significantWaveHeightM?.let{o.measuredAtUtc!! to it}},2);HorizontalDivider();MeasurementChart(tr("Скорост на вятъра","Wind speed"),"m/s",ordered.mapNotNull{o->o.windSpeedMs?.let{o.measuredAtUtc!! to it}},1);HorizontalDivider();MeasurementChart(tr("Интервал между вълните","Wave interval"),"s",ordered.mapNotNull{o->o.wavePeriodS?.let{o.measuredAtUtc!! to it}},1)}}}
@Composable private fun MeasurementChart(title:String,unit:String,points:List<Pair<java.time.Instant,Double>>,decimals:Int){Column(Modifier.fillMaxWidth(),verticalArrangement=Arrangement.spacedBy(6.dp)){Text(title,fontWeight=FontWeight.Bold);if(points.isEmpty()){Text(tr("Няма измерени данни","No measured data"),modifier=Modifier.height(40.dp))}else{Row(Modifier.fillMaxWidth()){points.forEach{(_,v)->Text("%.${decimals}f %s".format(v,unit),color=Color(0xFF0A9396),fontWeight=FontWeight.Bold,style=MaterialTheme.typography.labelMedium,textAlign=androidx.compose.ui.text.style.TextAlign.Center,modifier=Modifier.weight(1f))}};Canvas(Modifier.fillMaxWidth().height(48.dp)){val values=points.map{it.second};val low=(values.minOrNull()?:0.0);val high=(values.maxOrNull()?:1.0);val margin=((high-low)*.15).coerceAtLeast(.1);val range=(high-low+margin*2).coerceAtLeast(.2);val path=Path();points.forEachIndexed{i,p->val x=(i+.5f)*size.width/points.size;val y=size.height-6f-(((p.second-(low-margin))/range).toFloat()*(size.height-12f));if(i==0)path.moveTo(x,y)else path.lineTo(x,y);drawCircle(Color(0xFF006D77),5f,Offset(x,y))};drawPath(path,Color(0xFF0A9396),style=androidx.compose.ui.graphics.drawscope.Stroke(3f))};Row(Modifier.fillMaxWidth()){points.forEach{(time,_)->Text(time.atZone(ZoneId.of("Europe/Sofia")).format(DateTimeFormatter.ofPattern("HH:mm")),style=MaterialTheme.typography.labelSmall,textAlign=androidx.compose.ui.text.style.TextAlign.Center,modifier=Modifier.weight(1f))}}}}}
